using System.ComponentModel;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration – set OPENAI_API_KEY (or AZURE_OPENAI_ENDPOINT + key) and
// optionally OPENAI_MODEL before running.
// ---------------------------------------------------------------------------
var apiKey  = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? throw new InvalidOperationException("Set the OPENAI_API_KEY environment variable.");
var model   = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// ---------------------------------------------------------------------------
// Tool implementations
// ---------------------------------------------------------------------------
var notebook = new Notebook();

IChatClient client = new ChatClientBuilder(
        new OpenAIClient(apiKey).GetChatClient(model).AsIChatClient())
    .UseFunctionInvocation()          // automatically invoke tools
    .Build();

var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(WebSearch.SearchAsync),
        AIFunctionFactory.Create(notebook.SaveNote),
        AIFunctionFactory.Create(notebook.GetNotes),
    ],
};

// ---------------------------------------------------------------------------
// Agent loop
// ---------------------------------------------------------------------------
var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\n🔍  Researching: {topic}\n");

List<ChatMessage> history =
[
    new(ChatRole.System, """
        You are a research agent. Your goal is to thoroughly research the topic
        the user provides by using the available tools.

        Workflow:
        1. Break the topic into 2-3 search queries.
        2. Call web_search for each query.
        3. Call save_note to record every important finding (one fact per note).
        4. After gathering enough information, call get_notes to review your notes.
        5. Produce a well-structured Markdown summary with sections and references.

        Always cite the source URL when saving a note.
        """),
    new(ChatRole.User, $"Please research the following topic and provide a summary:\n\n{topic}"),
];

var response = await client.GetResponseAsync(history, chatOptions);

Console.WriteLine("\n────────────────────────────────────────────");
Console.WriteLine("📝  RESEARCH SUMMARY");
Console.WriteLine("────────────────────────────────────────────\n");
Console.WriteLine(response.Text);
Console.WriteLine();

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------
static string PromptForTopic()
{
    Console.Write("Enter a research topic: ");
    var input = Console.ReadLine()?.Trim();
    return string.IsNullOrEmpty(input) ? "Recent advances in quantum computing 2025-2026" : input;
}

// ---------------------------------------------------------------------------
// Web Search tool (uses DuckDuckGo Lite – no API key required)
// ---------------------------------------------------------------------------
static class WebSearch
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
        },
    };

    [Description("Search the web for information. Returns a list of result titles, snippets, and URLs.")]
    public static async Task<string> SearchAsync(
        [Description("The search query")] string query)
    {
        Console.WriteLine($"  🌐  Searching: \"{query}\"");
        try
        {
            var url = $"https://lite.duckduckgo.com/lite/?q={Uri.EscapeDataString(query)}";
            var html = await Http.GetStringAsync(url);
            var results = ParseResults(html);
            return results.Length == 0
                ? "No results found."
                : string.Join("\n\n", results.Take(5));
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    private static string[] ParseResults(string html)
    {
        // DuckDuckGo Lite returns simple HTML with result links in <a> tags
        // inside <td> elements with class "result-link" and snippets in
        // <td class="result-snippet">.
        var results = new List<string>();
        var linkTag = "class=\"result-link\"";
        var snippetTag = "class=\"result-snippet\"";
        int pos = 0;
        while (pos < html.Length && results.Count < 5)
        {
            int linkIdx = html.IndexOf(linkTag, pos, StringComparison.Ordinal);
            if (linkIdx < 0) break;

            var (title, href) = ExtractLink(html, linkIdx);
            string snippet = "";

            int snippetIdx = html.IndexOf(snippetTag, linkIdx, StringComparison.Ordinal);
            if (snippetIdx >= 0)
            {
                snippet = ExtractTextContent(html, snippetIdx);
                pos = snippetIdx + 1;
            }
            else
            {
                pos = linkIdx + linkTag.Length;
            }

            if (!string.IsNullOrWhiteSpace(title))
                results.Add($"Title: {title}\nURL: {href}\nSnippet: {snippet}");
        }
        return results.ToArray();
    }

    private static (string title, string href) ExtractLink(string html, int startFrom)
    {
        // Find the <a ...> tag that contains the class attribute
        int aStart = html.LastIndexOf("<a ", startFrom, Math.Min(startFrom, 200), StringComparison.Ordinal);
        if (aStart < 0) return ("", "");

        int aEnd = html.IndexOf('>', aStart);
        if (aEnd < 0) return ("", "");

        string tag = html[aStart..(aEnd + 1)];
        string href = ExtractAttribute(tag, "href");

        int closeA = html.IndexOf("</a>", aEnd, StringComparison.Ordinal);
        string title = closeA > aEnd
            ? StripTags(html[(aEnd + 1)..closeA]).Trim()
            : "";

        return (title, href);
    }

    private static string ExtractAttribute(string tag, string attr)
    {
        var search = $"{attr}=\"";
        int idx = tag.IndexOf(search, StringComparison.OrdinalIgnoreCase);
        if (idx < 0) return "";
        int start = idx + search.Length;
        int end = tag.IndexOf('"', start);
        return end > start ? tag[start..end] : "";
    }

    private static string ExtractTextContent(string html, int classAttrIdx)
    {
        int gt = html.IndexOf('>', classAttrIdx);
        if (gt < 0) return "";
        int closeTd = html.IndexOf("</td>", gt, StringComparison.OrdinalIgnoreCase);
        return closeTd > gt ? StripTags(html[(gt + 1)..closeTd]).Trim() : "";
    }

    private static string StripTags(string html)
    {
        var result = new System.Text.StringBuilder(html.Length);
        bool inTag = false;
        foreach (char c in html)
        {
            if (c == '<') { inTag = true; continue; }
            if (c == '>') { inTag = false; continue; }
            if (!inTag) result.Append(c);
        }
        return System.Net.WebUtility.HtmlDecode(result.ToString());
    }
}

// ---------------------------------------------------------------------------
// Note-taking tool – in-memory notebook the agent uses to collect findings
// ---------------------------------------------------------------------------
class Notebook
{
    private readonly List<string> _notes = [];

    [Description("Save a research note. Use this to record an important finding with its source URL.")]
    public string SaveNote(
        [Description("The fact or finding to record")] string note,
        [Description("Source URL for this finding")] string sourceUrl)
    {
        var entry = $"[{_notes.Count + 1}] {note} (source: {sourceUrl})";
        _notes.Add(entry);
        Console.WriteLine($"  📌  Note saved: {entry[..Math.Min(entry.Length, 90)]}…");
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Retrieve all saved research notes collected so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0) return "No notes saved yet.";
        Console.WriteLine($"  📒  Reviewing {_notes.Count} notes");
        return string.Join('\n', _notes);
    }
}

